 1	import React, { FC } from 'react';
 2	import { useLocation } from 'react-router-dom-v5-compat';
 3	
 4	import { VirtualMachineInstanceModelGroupVersionKind } from '@kubevirt-ui/kubevirt-api/console';
 5	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 6	import Loading from '@kubevirt-utils/components/Loading/Loading';
 7	import SidebarEditorSwitch from '@kubevirt-utils/components/SidebarEditor/SidebarEditorSwitch';
 8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 9	import useSingleNodeCluster from '@kubevirt-utils/hooks/useSingleNodeCluster';
10	import useVirtualMachineInstanceMigration from '@kubevirt-utils/resources/vmi/hooks/useVirtualMachineInstanceMigration';
11	import { isEmpty } from '@kubevirt-utils/utils/utils';
12	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
13	import { Label, Split, SplitItem } from '@patternfly/react-core';
14	import VirtualMachineActions from '@virtualmachines/actions/components/VirtualMachineActions/VirtualMachineActions';
15	import VMActionsIconBar from '@virtualmachines/actions/components/VMActionsIconBar/VMActionsIconBar';
16	import useVirtualMachineActionsProvider from '@virtualmachines/actions/hooks/useVirtualMachineActionsProvider';
17	import VirtualMachinePendingChangesAlert from '@virtualmachines/details/VirtualMachinePendingChangesAlert/VirtualMachinePendingChangesAlert';
18	import VMNotMigratableLabel from '@virtualmachines/list/components/VMNotMigratableLabel/VMNotMigratableLabel';
19	
20	import VirtualMachineBreadcrumb from '../list/components/VirtualMachineBreadcrumb/VirtualMachineBreadcrumb';
21	import { getVMStatusIcon } from '../utils';
22	
23	import { vmTabsWithYAML } from './utils/constants';
24	
25	type VirtualMachineNavPageTitleProps = {
26	  isLoaded?: boolean;
27	  name: string;
28	  nonExpandedVM: V1VirtualMachine;
29	  vm: V1VirtualMachine;
30	};
31	
32	const VirtualMachineNavPageTitle: FC<VirtualMachineNavPageTitleProps> = ({
33	  isLoaded,
34	  name,
35	  nonExpandedVM,
36	  vm,
37	}) => {
38	  const { t } = useKubevirtTranslation();
39	  const location = useLocation();
40	
41	  const [vmi] = useK8sWatchResource<V1VirtualMachineInstance>({
42	    groupVersionKind: VirtualMachineInstanceModelGroupVersionKind,
43	    isList: false,
44	    name: vm?.metadata?.name,
45	    namespace: vm?.metadata?.namespace,
46	  });
47	  const vmim = useVirtualMachineInstanceMigration(vm);
48	  const [isSingleNodeCluster] = useSingleNodeCluster();
49	  const [actions] = useVirtualMachineActionsProvider(nonExpandedVM, vmim, isSingleNodeCluster);
50	  const StatusIcon = getVMStatusIcon(vm?.status?.printableStatus);
51	
52	  const isSidebarEditorDisplayed = vmTabsWithYAML.find((tab) =>
53	    location.pathname.includes(`/${name}/${tab}`),
54	  );
55	
56	  return (
57	    <div className="co-m-nav-title co-m-nav-title--detail">
58	      <VirtualMachineBreadcrumb />
59	      <span className="co-m-pane__heading">
60	        <h1 className="co-resource-item__resource-name">
61	          <Split hasGutter>
62	            <SplitItem>
63	              <span className="co-m-resource-icon co-m-resource-icon--lg">{t('VM')}</span>
64	              {name}{' '}
65	              {!isEmpty(vm) && (
66	                <Label className="vm-resource-label" icon={<StatusIcon />} isCompact>
67	                  {vm?.status?.printableStatus}
68	                </Label>
69	              )}
70	              <VMNotMigratableLabel vm={vm} />
71	            </SplitItem>
72	          </Split>
73	        </h1>
74	        <Split hasGutter>
75	          {isSidebarEditorDisplayed && (
76	            <SplitItem className="VirtualMachineNavPageTitle__SidebarEditorSwitch">
77	              <SidebarEditorSwitch />
78	            </SplitItem>
79	          )}
80	          {!isLoaded && <Loading />}
81	          {vm && isLoaded && (
82	            <>
83	              <VMActionsIconBar vm={vm} />
84	              <SplitItem>
85	                <VirtualMachineActions actions={actions} />
86	              </SplitItem>
87	            </>
88	          )}
89	        </Split>
90	      </span>
91	      <VirtualMachinePendingChangesAlert vm={vm} vmi={vmi} />
92	    </div>
93	  );
94	};
95	
96	export default VirtualMachineNavPageTitle;

